external_knowledge:
; A championship event refers to a rally event that is part of a championship series; 
; Total penalty time is the sum of all penalty times a team incurred during an event; 
; Event order refers to the chronological order of events within a championship year.

sql:
SELECT event_name 
FROM events 
WHERE total_participants > (
  SELECT AVG(total_participants) 
  FROM events
);
